 1	import React, { FC } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { Operator } from '@openshift-console/dynamic-plugin-sdk-internal/lib/api/common-types';
 5	import { Button, ButtonVariant, GridItem, TextInput } from '@patternfly/react-core';
 6	import { MinusCircleIcon } from '@patternfly/react-icons';
 7	import { SimpleSelect } from '@patternfly/react-templates';
 8	
 9	import { AffinityLabel } from '../../../../utils/types';
10	
11	import { AffinityEditRowValues } from './AffinityEditRowValues';
12	
13	type AffinityExpressionRowProps = {
14	  expression: AffinityLabel;
15	  onChange: (label: AffinityLabel) => void;
16	  onDelete: (id: any) => void;
17	  rowID?: string;
18	};
19	
20	const AffinityExpressionRow: FC<AffinityExpressionRowProps> = ({
21	  expression,
22	  onChange,
23	  onDelete,
24	  rowID = 'affinity',
25	}) => {
26	  const { t } = useKubevirtTranslation();
27	  const { id, key, operator, values = [] } = expression;
28	  const enableValueField = operator !== Operator.Exists && operator !== Operator.DoesNotExist;
29	
30	  const onSelectOperator = (event, selection) => {
31	    onChange({ ...expression, operator: selection });
32	  };
33	
34	  const onSelectValues = (event, selection) => {
35	    const isValueExist = values.some((item) => item === selection);
36	    if (isValueExist) {
37	      onChange({ ...expression, values: values.filter((item) => item !== selection) });
38	    } else {
39	      onChange({ ...expression, values: [...values, selection] });
40	    }
41	  };
42	
43	  return (
44	    <>
45	      <GridItem span={4}>
46	        <TextInput
47	          id={`${rowID}-${id}-key-input`}
48	          isRequired
49	          onChange={(_event, newKey) => onChange({ ...expression, key: newKey })}
50	          placeholder={t('key')}
51	          type="text"
52	          value={key}
53	        />
54	      </GridItem>
55	      <GridItem span={2}>
56	        <SimpleSelect
57	          initialOptions={[Operator.Exists, Operator.DoesNotExist, Operator.In, Operator.NotIn].map(
58	            (operatorOption) => ({
59	              content: operatorOption,
60	              selected: operatorOption === operator,
61	              value: operatorOption,
62	            }),
63	          )}
64	          id={`${rowID}-${id}-effect-select`}
65	          onSelect={onSelectOperator}
66	        />
67	      </GridItem>
68	      <GridItem span={5}>
69	        <AffinityEditRowValues
70	          isHidden={!enableValueField}
71	          onClear={() => onChange({ ...expression, values: [] })}
72	          onSelect={onSelectValues}
73	          values={values}
74	        />
75	      </GridItem>
76	      <GridItem span={1}>
77	        <Button
78	          id={`${rowID}-${id}-delete-btn`}
79	          onClick={() => onDelete(id)}
80	          variant={ButtonVariant.plain}
81	        >
82	          <MinusCircleIcon />
83	        </Button>
84	      </GridItem>
85	    </>
86	  );
87	};
88	
89	export default AffinityExpressionRow;

